import math

def gcd(x, y):
    if y == 0:
        return x
    else:
        return gcd(y, x % y)

def main():
    t = int(input())  # Read the number of test cases
    for _ in range(t):
        n = int(input())  # Read the number of integers in this test case
        # Read the entire line, split by spaces, and convert to integers
        numbers = list(map(int, input().split()))

        ans = numbers[0]  # Initialize ans with the first number
        for a in numbers[1:]:  # Iterate over the rest of the numbers
            ans = gcd(ans, a)  # Update the GCD

        if ans != 1:
            # Find the smallest divisor greater than 1
            for j in range(2, int(math.sqrt(ans)) + 1):
                if ans % j == 0:
                    ans = j
                    break
            print(ans)  # Print the smallest divisor
        else:
            print("-1")  # Print -1 if the GCD is 1

if __name__ == "__main__":
    main()

