import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {

    // Method to calculate the GCD of two numbers
    public static int gcd(int x, int y) {
        if (y == 0) {
            return x;
        } else {
            return gcd(y, x % y);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Number of test cases
        int t = scanner.nextInt();

        while (t-- > 0) {
            // Number of elements
            int n = scanner.nextInt();
            int ans = 0; // To hold the GCD result

            // Reading the elements and calculating the GCD
            for (int i = 0; i < n; i++) {
                int a = scanner.nextInt();
                if (i == 0) {
                    ans = a; // Initialize ans with the first element
                }
                ans = gcd(ans, a); // Update GCD
            }

            // Finding the smallest prime factor
            if (ans != 1) {
                for (int j = 2; j * j <= ans; j++) {
                    if (ans % j == 0) {
                        ans = j; // Smallest prime factor found
                        break;
                    }
                }
                System.out.println(ans);
            } else {
                System.out.println("-1");
            }
        }

        scanner.close(); // Close the scanner
    }
}

code.JavaScript:
const readline = require('readline');

function gcd(x, y) {
    if (y === 0) {
        return x;
    } else {
        return gcd(y, x % y);
    }
}

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout,
    });

    const input = [];

    // Read input line by line
    rl.on('line', (line) => {
        input.push(line.trim());
    });

    rl.on('close', () => {
        let index = 0;
        const t = parseInt(input[index++]); // Read the number of test cases

        for (let i = 0; i < t; i++) {
            const n = parseInt(input[index++]); // Read the number of integers in this test case
            const numbers = input[index++].split(' ').map(Number); // Read and parse the numbers

            let ans = numbers[0]; // Initialize ans with the first number

            for (let j = 1; j < n; j++) { // Iterate over the rest of the numbers
                ans = gcd(ans, numbers[j]); // Update the GCD
            }

            if (ans !== 1) {
                // Find the smallest divisor greater than 1
                let smallestDivisor = -1;
                for (let j = 2; j <= Math.sqrt(ans); j++) {
                    if (ans % j === 0) {
                        smallestDivisor = j; // Found a divisor
                        break;
                    }
                }

                // If no divisor found, the GCD itself is the smallest divisor
                if (smallestDivisor === -1) {
                    smallestDivisor = ans; 
                }

                console.log(smallestDivisor); // Print the smallest divisor
            } else {
                console.log("-1"); // Print -1 if the GCD is 1
            }
        }
    });
}

main();
